import logging

import azure.functions as func
from azure.storage.blob import BlobServiceClient, BlobClient

def main(req: func.HttpRequest) -> func.HttpResponse:
    # Get blob path from query parameters
    blob_path = req.params.get('blobPath')

    if not blob_path:
        return func.HttpResponse(
            "Please pass a blobPath parameter in the query string",
            status_code=400
        )

    # Create BlobServiceClient and BlobClient objects
    blob_service_client = BlobServiceClient.from_connection_string(conn_str="YOUR_CONNECTION_STRING")
    blob_client = blob_service_client.get_blob_client(blob_path)

    # Read the file directly from Azure Storage using the BlobClient object
    with open("output.txt", "wb") as f:
        f.write(blob_client.download_blob().readall())

    # Return a success response
    return func.HttpResponse(f"File downloaded successfully to output.txt!", status_code=200)